  'data.delete_account_desc': { fr: 'Supprime définitivement votre espace Illizeo et toutes les données associées. Cette action est irréversible et prend effet sous 30 jours.', en: 'Permanently deletes your Illizeo workspace and all associated data. This action is irreversible and takes effect within 30 days.', de: 'Löscht dauerhaft Ihren Illizeo-Arbeitsbereich und alle zugehörigen Daten. Diese Aktion ist unwiderruflich.', it: "Elimina definitivamente il tuo spazio Illizeo e tutti i dati associati. Questa azione è irreversibile.", es: 'Elimina permanentemente su espacio Illizeo y todos los datos asociados. Esta acción es irreversible.' },
  'data.delete_account_confirm': { fr: "ATTENTION : Cette action supprimera définitivement votre espace Illizeo, tous les utilisateurs, collaborateurs, parcours, documents et données associées. Cette action est irréversible. Êtes-vous absolument certain ?", en: 'WARNING: This action will permanently delete your Illizeo workspace, all users, employees, paths, documents and associated data. This action is irreversible. Are you absolutely sure?', de: 'ACHTUNG: Diese Aktion löscht dauerhaft Ihren Illizeo-Arbeitsbereich. Sind Sie absolut sicher?', it: "ATTENZIONE: Questa azione eliminerà definitivamente il tuo spazio Illizeo. Sei assolutamente sicuro?", es: '¡ATENCIÓN! Esta acción eliminará permanentemente su espacio Illizeo. ¿Está absolutamente seguro?' },
  'data.delete_account_success': { fr: 'Demande de suppression enregistrée. Vous recevrez un email de confirmation sous 24h.', en: 'Deletion request registered. You will receive a confirmation email within 24h.', de: 'Löschantrag registriert. Sie erhalten innerhalb von 24 Stunden eine Bestätigungs-E-Mail.', it: "Richiesta di eliminazione registrata. Riceverai un'email di conferma entro 24 ore.", es: 'Solicitud de eliminación registrada. Recibirá un email de confirmación en 24h.' },
